        if (!Isvisible)
        {
            StartPC();
        }
        else
        {
            ShutDownPC();
        }
    }

    private void StartPC()
    {
        canvas.SetActive(true);
        source.clip = StartSound;
        source.Play();
        Isvisible = true;
    }

    private void ShutDownPC()
    {
        canvas.SetActive(false);
        source.clip = EndSound;
        source.Play();
        Isvisible = false;
    }
}
